def draw_realistic_knife(surf, rect, direction, alpha=255):
    angle = 0
    if direction == 'up': angle = 0
    elif direction == 'down': angle = 180
    elif direction == 'left': angle = 90
    elif direction == 'right': angle = -90
    elif isinstance(direction, (int, float)): angle = direction

    img = BASE_KNIFE_IMG.copy()
    if alpha < 255:
        img.set_alpha(alpha)

    rotated_img = pygame.transform.rotate(img, angle)
    new_rect = rotated_img.get_rect(center=rect.center)
    surf.blit(rotated_img, new_rect.topleft)

def spawn_knife(side_override=None):
    side = side_override if side_override is not None else random.randint(0, 3)
    speed = random.randint(7, 12) 
    
    K_LONG = 55
    K_SHORT = 18

    if side == 0:
        x = random.randint(arena_rect.left, arena_rect.right - K_SHORT)
        y = -100
        return pygame.Rect(x, y, K_SHORT, K_LONG), 0, speed, 'down', 0
    elif side == 1: 
        x = random.randint(arena_rect.left, arena_rect.right - K_SHORT)
        y = HEIGHT + 100
        return pygame.Rect(x, y, K_SHORT, K_LONG), 0, -speed, 'up', 0
    elif side == 2: 
        x = -100
        y = random.randint(arena_rect.top, arena_rect.bottom - K_SHORT)
        return pygame.Rect(x, y, K_LONG, K_SHORT), speed, 0, 'right', 0
    else: 
        x = WIDTH + 100
        y = random.randint(arena_rect.top, arena_rect.bottom - K_SHORT)
        return pygame.Rect(x, y, K_LONG, K_SHORT), -speed, 0, 'left', 0

def game_over_screen(player_rect):
    global hit_sound
    alpha = 255
    fade_speed = 2
    
    while alpha > 0:
        for e in pygame.event.get():
            if e.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
                
            if e.type == PLAY_HIT_SOUND:
                if hit_sound:
                    hit_sound.play()
                    
        screen.fill(BLACK)
        temp_player_surf = pygame.Surface((PLAYER_W, PLAYER_H), pygame.SRCALPHA)
        temp_player_surf.fill((255, 0, 0, alpha))
        screen.blit(temp_player_surf, player_rect.topleft)
        pygame.display.flip()
        
        alpha -= fade_speed
        clock.tick(FPS)
    
    pygame.time.delay(500)

    while True:
        screen.fill(BLACK)
        text1 = font_big.render("살해 당했습니다..", True, RED)
        text2 = font.render("다시 시작 'R'", True, WHITE)
        text3 = font.render("종료 'Q'", True, GRAY)
        
        screen.blit(text1, (WIDTH // 2 - text1.get_width() // 2, HEIGHT // 2 - 80))
        screen.blit(text2, (WIDTH // 2 - text2.get_width() // 2, HEIGHT // 2 + 10))
        screen.blit(text3, (WIDTH // 2 - text3.get_width() // 2, HEIGHT // 2 + 70))
        pygame.display.flip()
        
        for e in pygame.event.get():
            if e.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            if e.type == pygame.KEYDOWN:
                if e.key == pygame.K_r: 
                    return
                if e.key == pygame.K_q:
                    pygame.quit()
                    sys.exit()

def create_multicolor_surface(lines, font_obj):
    surfaces = []
    max_w = 0
    total_h = 0
    for line in lines:
        line_w = 0
        line_h = 0
        rendered_chunks = []
        for text, color in line:
            chunk = font_obj.render(text, True, color)
            rendered_chunks.append(chunk)
            line_w += chunk.get_width()
            line_h = max(line_h, chunk.get_height())
        surfaces.append((rendered_chunks, line_w, line_h))
        max_w = max(max_w, line_w)
        total_h += line_h + 10

    main_surf = pygame.Surface((max_w, total_h), pygame.SRCALPHA)
    current_y = 0
    for chunks, lw, lh in surfaces:
        current_x = (max_w - lw) // 2 
        for chunk in chunks:
            main_surf.blit(chunk, (current_x, current_y))
            current_x += chunk.get_width()
        current_y += lh + 10
    return main_surf

# 👉 스토리 화면을 출력해주는 함수
def story_intro_screen():
    # 스토리음악 재생
    try:
        pygame.mixer.music.load("./code/week06/assets/sounds/스토리음.mp3")
        pygame.mixer.music.set_volume(0.03)   
        pygame.mixer.music.play(-1)
    except:
        pass

    # 문장 리스트 (텍스트, 색상)
    scenes = [
        [ [("호서대에 입학해 열심히 생활 중인 ", WHITE), ("플레이어", PLAYER_BLUE), (".", WHITE)] ],
        [ 
            [("저 멀리 ", WHITE), ("플레이어", PLAYER_BLUE), ("를 좋아하는 ", WHITE)],
            [("얀데레", RED), ("가 몰래 쳐다보고 있다.", WHITE)] 
        ],
        [ [("점심시간, ", WHITE), ("플레이어", PLAYER_BLUE), ("가 점심 먹으러 가던 길.", WHITE)] ],
        [ 
            [("같은 과에", WHITE),(" 활기찬 여자아이", YELLOW), ("가 ", WHITE), ("플레이어", PLAYER_BLUE), ("의", WHITE) ],
            [("팔짱을", WHITE),  (" 끼고 같이 점심을 먹으러 가고있다.", WHITE)] 
        ],
        [ [("웃고있는 ", WHITE), ("플레이어", PLAYER_BLUE), ("의 얼굴을 본 ", WHITE), ("얀데레", RED), (".", WHITE)] ],
        [ [("그녀", RED),("는 속삭였다...", WHITE)] ]
    ]
    
    for scene_lines in scenes:
        total_chars = sum(len(text) for line in scene_lines for text, color in line)
        
        displayed_chars = 0
        char_speed = 0.25 
        waiting_for_next = True
        
        while waiting_for_next:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    sys.exit()
                elif event.type == pygame.KEYDOWN:
                    # 💡 메뉴 진입 전에 x를 누르면 바로 게임이 종료되도록 설정
                    if event.key == pygame.K_x:
                        pygame.quit()
                        sys.exit()
                    elif event.key == pygame.K_RETURN:
                        if displayed_chars < total_chars:
                            displayed_chars = total_chars
                        else:
                            waiting_for_next = False
            
            screen.fill(BLACK)
            
            if displayed_chars < total_chars:
                displayed_chars += char_speed
                
            partial_scene = []
            chars_left = int(displayed_chars)
            for line in scene_lines:
                partial_line = []
                for text, color in line:
                    if chars_left <= 0:
                        break
                    if len(text) <= chars_left:
                        partial_line.append((text, color))
                        chars_left -= len(text)
                    else:
                        partial_line.append((text[:chars_left], color))
                        chars_left = 0
                if partial_line:
                    partial_scene.append(partial_line)
                if chars_left <= 0:
                    break
                    
            if partial_scene:
                surf = create_multicolor_surface(partial_scene, font_mid)
                rect = surf.get_rect(center=(WIDTH//2, HEIGHT//2))
                screen.blit(surf, rect)
            
            if displayed_chars >= total_chars:
                info_surf = font_small.render("엔터(Enter)를 눌러 계속...", True, GRAY)
                if (pygame.time.get_ticks() // 600) % 2 == 0:
                    info_rect = info_surf.get_rect(center=(WIDTH//2, HEIGHT - 50))
                    screen.blit(info_surf, info_rect)
            
            pygame.display.flip()
            clock.tick(FPS)
            
    # 마지막 [죽어.] 씬
    die_surf = font_huge.render("\"죽어.\"", True, RED)
    
    # 죽어 씬 배경음악 재생
    pygame.mixer.music.stop()
    try:
        pygame.mixer.music.load("./code/week06/assets/sounds/죽어음.wav")
        pygame.mixer.music.set_volume(0.03)   
        pygame.mixer.music.play(-1)
    except:
        pass

    info_surf = font_small.render("Enter를 눌러 게임 시작", True, GRAY)
    
    blink_timer = 0
    waiting_for_start = True
    while waiting_for_start:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_RETURN:
                    waiting_for_start = False # 루프 탈출 후 달려오는 애니메이션 시작
        
        screen.fill(BLACK)
        
        die_rect = die_surf.get_rect(center=(WIDTH//2, HEIGHT//2 - 50))
        screen.blit(die_surf, die_rect)
        
        blink_timer += 1
        if (blink_timer // 30) % 2 == 0:
            info_rect = info_surf.get_rect(center=(WIDTH//2, HEIGHT//2 + 80))
            screen.blit(info_surf, info_rect)
            
        pygame.display.flip()
        clock.tick(FPS)

    # ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
    # 👉 추가된 얀데레 달려오는 점프스케어 연출 (달리기 모션 사용)
    # ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
    scale = 1.0
    frame_index = 0
    anim_timer = 0
    
    # 화면을 완전히 덮을 정도로 스케일이 커질 때까지 루프
    while scale < 30.0:
        dt = clock.tick(FPS)
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()

        anim_timer += dt
        if anim_timer >= FRAME_DELAY:
            frame_index = (frame_index + 1) % len(run_anim_sequence)
            anim_timer = 0

        # 스케일 확대 속도
        scale += 0.6

        screen.fill(BLACK)
        # 붉은 '죽어' 텍스트는 뒤에 유지
        screen.blit(die_surf, die_rect)

        # 달리기 모션(run_anim_sequence) 적용
        current_frame = run_anim_sequence[frame_index]
        
        new_w = int(FRAME_W * scale)
        new_h = int(FRAME_H * scale)
        scaled_img = pygame.transform.scale(current_frame, (new_w, new_h))
        
        # 확대된 캐릭터를 화면 중앙에 배치
        img_rect = scaled_img.get_rect(center=(WIDTH//2, HEIGHT//2))
        screen.blit(scaled_img, img_rect)
        
        pygame.display.flip()
    

    return 

